/// Executor for AccountDeletion flow
pub struct AccountDeletionFlowExecutor<H: AccountDeletionStepHandler> {
    handler: Arc<H>,
}

impl<H: AccountDeletionStepHandler> AccountDeletionFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<AccountDeletionFlowInstance, FlowError> {
        let mut instance = AccountDeletionFlowInstance::new(instance_id);
        instance.status = AccountDeletionFlowStatus::Running;
        instance.current_step = Some(AccountDeletionFlowStep::GetUser);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut AccountDeletionFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            AccountDeletionFlowStep::GetUser => {
                self.handler.handle_get_user(instance).await?
            }
            AccountDeletionFlowStep::ValidateRequest => {
                let next = self.handler.evaluate_validate_request(instance).await?;
                Some(next)
            }
            AccountDeletionFlowStep::CheckSelfRequest => {
                let next = self.handler.evaluate_check_self_request(instance).await?;
                Some(next)
            }
            AccountDeletionFlowStep::RequirePasswordConfirmation => {
                self.handler.handle_require_password_confirmation(instance).await?
            }
            AccountDeletionFlowStep::CheckGracePeriod => {
                let next = self.handler.evaluate_check_grace_period(instance).await?;
                Some(next)
            }
            AccountDeletionFlowStep::StartGracePeriod => {
                self.handler.handle_start_grace_period(instance).await?
            }
            AccountDeletionFlowStep::SendDeletionScheduledEmail => {
                self.handler.handle_send_deletion_scheduled_email(instance).await?
            }
            AccountDeletionFlowStep::LogDeletionScheduled => {
                self.handler.handle_log_deletion_scheduled(instance).await?
            }
            AccountDeletionFlowStep::WaitGracePeriod => {
                self.handler.handle_wait_grace_period(instance).await?
            }
            AccountDeletionFlowStep::HandleCancellation => {
                self.handler.handle_handle_cancellation(instance).await?
            }
            AccountDeletionFlowStep::SendCancellationEmail => {
                self.handler.handle_send_cancellation_email(instance).await?
            }
            AccountDeletionFlowStep::CancellationComplete => {
                self.handler.handle_cancellation_complete(instance).await?;
                None // Terminal step
            }
            AccountDeletionFlowStep::AdminDeletionPath => {
                let next = self.handler.evaluate_admin_deletion_path(instance).await?;
                Some(next)
            }
            AccountDeletionFlowStep::ProceedWithDeletion => {
                self.handler.handle_proceed_with_deletion(instance).await?
            }
            AccountDeletionFlowStep::OfferDataExport => {
                self.handler.handle_offer_data_export(instance).await?
            }
            AccountDeletionFlowStep::SendDataExportEmail => {
                self.handler.handle_send_data_export_email(instance).await?
            }
            AccountDeletionFlowStep::RevokeAllSessions => {
                self.handler.handle_revoke_all_sessions(instance).await?
            }
            AccountDeletionFlowStep::DeleteMfaDevices => {
                self.handler.handle_delete_mfa_devices(instance).await?
            }
            AccountDeletionFlowStep::DeletePasswordTokens => {
                self.handler.handle_delete_password_tokens(instance).await?
            }
            AccountDeletionFlowStep::DeleteSessions => {
                self.handler.handle_delete_sessions(instance).await?
            }
            AccountDeletionFlowStep::DeleteUserSettings => {
                self.handler.handle_delete_user_settings(instance).await?
            }
            AccountDeletionFlowStep::DeleteProfile => {
                self.handler.handle_delete_profile(instance).await?
            }
            AccountDeletionFlowStep::RevokeUserPermissions => {
                self.handler.handle_revoke_user_permissions(instance).await?
            }
            AccountDeletionFlowStep::RevokeUserRoles => {
                self.handler.handle_revoke_user_roles(instance).await?
            }
            AccountDeletionFlowStep::AnonymizeAuditLogs => {
                self.handler.handle_anonymize_audit_logs(instance).await?
            }
            AccountDeletionFlowStep::SoftDeleteUser => {
                self.handler.handle_soft_delete_user(instance).await?
            }
            AccountDeletionFlowStep::LogDeletionComplete => {
                self.handler.handle_log_deletion_complete(instance).await?
            }
            AccountDeletionFlowStep::ScheduleHardDelete => {
                self.handler.handle_schedule_hard_delete(instance).await?
            }
            AccountDeletionFlowStep::Complete => {
                self.handler.handle_complete(instance).await?;
                None // Terminal step
            }
            AccountDeletionFlowStep::ErrorAlreadyDeleted => {
                self.handler.handle_error_already_deleted(instance).await?;
                None // Terminal step
            }
            AccountDeletionFlowStep::ConfirmationTimeout => {
                self.handler.handle_confirmation_timeout(instance).await?
            }
            AccountDeletionFlowStep::TimeoutEnd => {
                self.handler.handle_timeout_end(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = AccountDeletionFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut AccountDeletionFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != AccountDeletionFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut AccountDeletionFlowInstance) {
        instance.status = AccountDeletionFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut AccountDeletionFlowInstance, error: impl Into<String>) {
        instance.status = AccountDeletionFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = AccountDeletionFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, AccountDeletionFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = AccountDeletionFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = AccountDeletionFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = AccountDeletionFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = AccountDeletionFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}